            return (s, address(uint160(v)));
        } else {
            return (false, address(0));
        }
    }

    function _tryParseChr(bytes1 chr) private pure returns (uint8) {
        uint8 value = uint8(chr);

        // Try to parse `chr`:
        // - Case 1: [0-9]
        // - Case 2: [a-f]
        // - Case 3: [A-F]
        // - otherwise not supported
        unchecked {
            if (value > 47 && value < 58) value -= 48;
            else if (value > 96 && value < 103) value -= 87;
            else if (value > 64 && value < 71) value -= 55;
            else return type(uint8).max;
        }

        return value;
    }

    /**
     * @dev Escape special characters in JSON strings. This can be useful to prevent JSON injection in NFT metadata.
     *
     * WARNING: This function should only be used in double quoted JSON strings. Single quotes are not escaped.
     *
     * NOTE: This function escapes backslashes (including those in \uXXXX sequences) and the characters in ranges
     * defined in section 2.5 of RFC-4627 (U+0000 to U+001F, U+0022 and U+005C). All control characters in U+0000
     * to U+001F are escaped (\b, \t, \n, \f, \r use short form; others use \u00XX). ECMAScript's `JSON.parse` does
     * recover escaped unicode characters that are not in this range, but other tooling may provide different results.
     */
    function escapeJSON(string memory input) internal pure returns (string memory) {
        bytes memory buffer = bytes(input);

        // Put output at the FMP. Memory will be reserved later when we figure out the actual length of the escaped
        // string. All write are done using _unsafeWriteBytesOffset, which avoid the (expensive) length checks for
        // each character written.
        bytes memory output;
        assembly ("memory-safe") {
            output := mload(0x40)
        }
        uint256 outputLength = 0;

        for (uint256 i = 0; i < buffer.length; ++i) {
            uint8 char = uint8(bytes1(_unsafeReadBytesOffset(buffer, i)));
            if (((SPECIAL_CHARS_LOOKUP & (1 << char)) != 0)) {
                _unsafeWriteBytesOffset(output, outputLength++, "\\");
                if (char == 0x08) _unsafeWriteBytesOffset(output, outputLength++, "b");
                else if (char == 0x09) _unsafeWriteBytesOffset(output, outputLength++, "t");
                else if (char == 0x0a) _unsafeWriteBytesOffset(output, outputLength++, "n");
                else if (char == 0x0c) _unsafeWriteBytesOffset(output, outputLength++, "f");
                else if (char == 0x0d) _unsafeWriteBytesOffset(output, outputLength++, "r");
                else if (char == 0x5c) _unsafeWriteBytesOffset(output, outputLength++, "\\");
                else if (char == 0x22) {
                    // solhint-disable-next-line quotes
                    _unsafeWriteBytesOffset(output, outputLength++, '"');
                } else {
                    // U+0000 to U+001F without short form: output \u00XX
                    _unsafeWriteBytesOffset(output, outputLength++, "u");
                    _unsafeWriteBytesOffset(output, outputLength++, "0");
                    _unsafeWriteBytesOffset(output, outputLength++, "0");
                    _unsafeWriteBytesOffset(output, outputLength++, HEX_DIGITS[char >> 4]);
                    _unsafeWriteBytesOffset(output, outputLength++, HEX_DIGITS[char & 0x0f]);
                }
            } else {
                _unsafeWriteBytesOffset(output, outputLength++, bytes1(char));
            }
        }
        // write the actual length and reserve memory
        assembly ("memory-safe") {
            mstore(output, outputLength)
            mstore(0x40, add(output, add(outputLength, 0x20)))
        }

        return string(output);
    }

    /**
     * @dev Reads a bytes32 from a bytes array without bounds checking.
     *
     * NOTE: making this function internal would mean it could be used with memory unsafe offset, and marking the
     * assembly block as such would prevent some optimizations.
     */
    function _unsafeReadBytesOffset(bytes memory buffer, uint256 offset) private pure returns (bytes32 value) {
        // This is not memory safe in the general case, but all calls to this private function are within bounds.
        assembly ("memory-safe") {
            value := mload(add(add(buffer, 0x20), offset))
        }
    }

    /**
     * @dev Write a bytes1 to a bytes array without bounds checking.
     *
     * NOTE: making this function internal would mean it could be used with memory unsafe offset, and marking the
     * assembly block as such would prevent some optimizations.
     */
    function _unsafeWriteBytesOffset(bytes memory buffer, uint256 offset, bytes1 value) private pure {
        // This is not memory safe in the general case, but all calls to this private function are within bounds.
        assembly ("memory-safe") {
            mstore8(add(add(buffer, 0x20), offset), shr(248, value))
        }
    }
}

contracts/LendingPool.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "./ReputationNFT.sol";

/**
 * @title LendingPool
 * @author TrustLend Team
 * @notice Core lending contract for TrustLend — a decentralised micro-lending
 *         platform on Polygon Amoy. Manages pool liquidity, borrower loans,
 *         trust-score-gated limits, interest accrual, and auto-scoring on repayment.
 *
 * @dev Architecture
 *  ┌──────────┐   depositToPool()   ┌──────────┐   requestLoan()   ┌──────────┐
 *  │  Lender  │ ──────────────────▶ │   Pool   │ ─────────────────▶│ Borrower │
 *  └──────────┘                     └──────────┘                    └──────────┘
 *       ▲                                ▲                               │
 *       │  withdrawFromPool()            │  makeRepayment()              │
 *       └────────────────────────────────┘◀──────────────────────────────┘
 *
 * Key features:
 *  • Trust-score-gated borrow limits (30–100 → $10–$500)
 *  • Three loan paths with path-specific interest rates
 *  • Automatic trust score adjustments on repayment
 *  • Proportional yield distribution to lenders
 *  • ReentrancyGuard + Pausable safety
 */
contract LendingPool is Ownable, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    /* ══════════════════════════════════════════
       ENUMS
    ═══════════════════════════════════════════ */

    /// @notice Loan lifecycle status.
    enum LoanStatus { Active, Repaid, Defaulted, Liquidated }

    /// @notice Determines interest rate applied to the loan.
    enum LoanPath  { VouchBacked, Collateral, TrustOnly }

    /* ══════════════════════════════════════════
       STRUCTS
    ═══════════════════════════════════════════ */

    /// @notice Full loan record for a borrower.
    struct Loan {
        address    borrower;
        uint256    amount;            // principal in TRUST (18 dec)
        uint256    repaidAmount;      // total TRUST repaid so far
        uint256    interestRate;      // basis points (e.g. 500 = 5%)
        uint256    startTime;         // block.timestamp at disbursal
        uint256    dueDate;           // startTime + durationDays
        uint8      installmentsPaid;  // repayment count
        uint8      totalInstallments; // how many equal payments expected
        LoanStatus status;
        LoanPath   path;
    }

    /* ══════════════════════════════════════════
       STATE
    ═══════════════════════════════════════════ */

    /// @notice The TRUST ERC-20 token used for all pool operations.
    IERC20 public immutable trustToken;

    /// @notice The heart of our reputation identity — the soulbound NFT.
    address public reputationNFT;

    /// @dev borrower → active Loan (one active loan per borrower)
    mapping(address => Loan) private _loans;

    /// @dev lender → principal deposited (before yield)
    mapping(address => uint256) public lenderDeposits;

    /// @dev borrower → on-chain trust score (0–100)
    mapping(address => uint8)   public trustScores;

    /// @notice Sum of all lender deposits currently in the pool (excl. active loans).
    uint256 public totalPoolLiquidity;

    /// @notice Number of loans currently in Active status.
    uint256 public totalActiveLoans;

    /// @notice Running count of all unique lenders who deposited ≥ once.
    uint256 public totalLenders;

    /// @notice Sum of all interest rates across active loans (for avg calc).
    uint256 private _activeInterestSum;

    /// @dev tracks first-time lenders
    mapping(address => bool) private _hasDeposited;

    /* ══════════════════════════════════════════
       CONSTANTS
    ═══════════════════════════════════════════ */

    /// @dev Basis-point interest rates per path
    uint256 private constant RATE_VOUCH      = 420;   // 4.2%
    uint256 private constant RATE_COLLATERAL = 280;   // 2.8%
    uint256 private constant RATE_TRUST_ONLY = 710;   // 7.1%

    /// @dev Trust score bands → maximum borrow amounts (in TRUST, 18 decimals)
    uint256 private constant LIMIT_ENTRY    = 10   * 1e18;  // score 30-39
    uint256 private constant LIMIT_BRONZE   = 50   * 1e18;  // score 40-59
    uint256 private constant LIMIT_SILVER   = 200  * 1e18;  // score 60-79
    uint256 private constant LIMIT_GOLD     = 500  * 1e18;  // score 80-100

    /// @dev Default number of equal installments per loan
    uint8 private constant DEFAULT_INSTALLMENTS = 4;

    /// @dev Score adjustments on repayment
    uint8 private constant SCORE_ONTIME = 8;
    uint8 private constant SCORE_EARLY  = 12;
    uint8 private constant SCORE_LATE   = 3;

    /// @dev Maximum trust score ceiling
    uint8 private constant MAX_SCORE = 100;

    /* ══════════════════════════════════════════
       EVENTS
    ═══════════════════════════════════════════ */

    /// @notice Emitted when a lender deposits TRUST into the pool.
    event PoolDeposit(
        address indexed lender,
        uint256 amount,
        uint256 newTotal
    );

    /// @notice Emitted when a lender withdraws TRUST from the pool.
    event PoolWithdrawal(
        address indexed lender,
        uint256 amount,
        uint256 yieldEarned
    );

    /// @notice Emitted when a loan is created and funds disbursed.
    event LoanDisbursed(
        address indexed borrower,
        uint256 amount,
        uint256 dueDate,
        LoanPath path
    );

    /// @notice Emitted for each repayment (partial or full).
    event RepaymentMade(
        address indexed borrower,
        uint256 amount,
        uint256 remaining,
        uint8   newTrustScore
    );

    /// @notice Emitted when a trust score is updated (by owner or internally).
    event TrustScoreUpdated(
        address indexed borrower,
        uint8   oldScore,
        uint8   newScore
    );

    /// @notice Emitted when a loan is marked as defaulted.
    event LoanDefaulted(
        address indexed borrower,
        uint256 amount,
        uint256 outstandingDebt
    );

    /* ══════════════════════════════════════════
       CONSTRUCTOR
    ═══════════════════════════════════════════ */

    /**
     * @notice Deploy the LendingPool tied to a specific TRUST token.
     * @param _trustToken Address of the TrustToken ERC-20 contract.
     * @param _reputationNFT Address of the ReputationNFT contract.
     */
    constructor(address _trustToken, address _reputationNFT) Ownable(msg.sender) {
        require(_trustToken != address(0), "LendingPool: zero token address");
        require(_reputationNFT != address(0), "LendingPool: zero NFT address");
        trustToken = IERC20(_trustToken);
        reputationNFT = _reputationNFT;
    }

    /* ══════════════════════════════════════════
       LENDER FUNCTIONS
    ═══════════════════════════════════════════ */

    /**
     * @notice Deposit TRUST tokens into the lending pool.
     * @dev    Caller must first `approve` this contract for `amount`.
     * @param  amount Amount of TRUST to deposit (18 decimals).
     *
     * Emits {PoolDeposit}.
     */
    function depositToPool(uint256 amount) external nonReentrant whenNotPaused {
        require(amount > 0, "LendingPool: zero deposit");

        trustToken.safeTransferFrom(msg.sender, address(this), amount);

        lenderDeposits[msg.sender] += amount;
        totalPoolLiquidity += amount;

        if (!_hasDeposited[msg.sender]) {
            _hasDeposited[msg.sender] = true;
            totalLenders++;
        }

        emit PoolDeposit(msg.sender, amount, totalPoolLiquidity);
    }

    /**
     * @notice Withdraw deposited TRUST from the pool.
     * @dev    Withdrawal is limited to the pool's available (non-loaned) liquidity.
     *         Yield is calculated as a proportional share of interest earnings held
     *         by the contract above totalPoolLiquidity.
     * @param  amount Principal amount to withdraw.
     *
     * Emits {PoolWithdrawal}.
     */
    function withdrawFromPool(uint256 amount) external nonReentrant whenNotPaused {
        require(amount > 0, "LendingPool: zero withdrawal");
        require(lenderDeposits[msg.sender] >= amount, "LendingPool: exceeds deposit");
        require(totalPoolLiquidity >= amount, "LendingPool: insufficient free liquidity");

        // Calculate yield: proportional share of contract's surplus over pool deposits
        uint256 contractBalance = trustToken.balanceOf(address(this));
        uint256 yieldEarned = 0;
        if (contractBalance > totalPoolLiquidity && totalPoolLiquidity > 0) {
            uint256 surplus = contractBalance - totalPoolLiquidity;
            yieldEarned = (surplus * amount) / totalPoolLiquidity;
        }

        lenderDeposits[msg.sender] -= amount;
        totalPoolLiquidity -= amount;

        uint256 totalPayout = amount + yieldEarned;
        trustToken.safeTransfer(msg.sender, totalPayout);

        emit PoolWithdrawal(msg.sender, amount, yieldEarned);
    }

    /* ══════════════════════════════════════════
       BORROWER FUNCTIONS
    ═══════════════════════════════════════════ */

    /**
     * @notice Request a loan. Funds are immediately disbursed if all checks pass.
     * @dev    - Borrower must NOT have an existing Active loan.
     *         - Amount must be within the borrower's trust-score-based limit.
     *         - Pool must have sufficient free liquidity.
     *         Interest rate is determined by the chosen `path`.
     * @param  amount       Loan principal in TRUST (18 decimals).
     * @param  durationDays Loan term in days.
     * @param  path         0 = VouchBacked, 1 = Collateral, 2 = TrustOnly.
     *
     * Emits {LoanDisbursed}.
     */
    function requestLoan(
        uint256 amount,
        uint256 durationDays,
        uint8   path
    ) external nonReentrant whenNotPaused {
        require(amount > 0, "LendingPool: zero amount");
        require(durationDays > 0 && durationDays <= 365, "LendingPool: invalid duration");
        require(path <= uint8(LoanPath.TrustOnly), "LendingPool: invalid path");

        // One active loan per borrower
        require(
            _loans[msg.sender].status != LoanStatus.Active,
            "LendingPool: active loan exists"
        );

        // Trust-score-gated limit
        uint256 limit = getBorrowLimit(msg.sender);
        require(amount <= limit, "LendingPool: exceeds trust limit");

        // Pool liquidity check
        require(totalPoolLiquidity >= amount, "LendingPool: insufficient pool liquidity");

        // Determine interest rate
        LoanPath loanPath = LoanPath(path);
        uint256 rate = _rateForPath(loanPath);

        // Build loan
        uint256 dueDate = block.timestamp + (durationDays * 1 days);
        _loans[msg.sender] = Loan({
            borrower:          msg.sender,
            amount:            amount,
            repaidAmount:      0,
            interestRate:      rate,
            startTime:         block.timestamp,
            dueDate:           dueDate,
            installmentsPaid:  0,
            totalInstallments: DEFAULT_INSTALLMENTS,
            status:            LoanStatus.Active,
            path:              loanPath
        });

        totalPoolLiquidity -= amount;
        totalActiveLoans++;
        _activeInterestSum += rate;

        // Disburse
        trustToken.safeTransfer(msg.sender, amount);

        emit LoanDisbursed(msg.sender, amount, dueDate, loanPath);
    }

    /**
     * @notice Repay part or all of an active loan.
     * @dev    On full repayment the loan is marked Repaid and `_increaseTrustScore`
     *         is called to reward the borrower. Interest gained stays in the pool
     *         and is distributed proportionally to lenders on withdrawal.
     * @param  amount TRUST tokens to repay (caller must have approved this contract).
     *
     * Emits {RepaymentMade}.
     */
    function makeRepayment(uint256 amount) external nonReentrant whenNotPaused {
        Loan storage loan = _loans[msg.sender];
        require(loan.status == LoanStatus.Active, "LendingPool: no active loan");
        require(amount > 0, "LendingPool: zero repayment");

        // Total owed = principal + interest
        uint256 totalOwed = _totalOwed(loan);
        uint256 remaining = totalOwed - loan.repaidAmount;
        require(amount <= remaining, "LendingPool: overpayment");

        // Pull tokens
        trustToken.safeTransferFrom(msg.sender, address(this), amount);

        loan.repaidAmount += amount;
        loan.installmentsPaid++;

        // Return principal portion to pool liquidity
        // (interest stays in the contract as yield for lenders)
        uint256 principalPortion = (amount * loan.amount) / totalOwed;
        totalPoolLiquidity += principalPortion;

        // Check if fully repaid
        if (loan.repaidAmount >= totalOwed) {
            loan.status = LoanStatus.Repaid;
            totalActiveLoans--;
            _activeInterestSum -= loan.interestRate;
            _increaseTrustScore(msg.sender);
        }

        uint8 currentScore = trustScores[msg.sender];
        remaining = totalOwed - loan.repaidAmount;

        emit RepaymentMade(msg.sender, amount, remaining, currentScore);
    }

    /* ══════════════════════════════════════════
       ADMIN FUNCTIONS
    ═══════════════════════════════════════════ */

    /**
     * @notice Owner updates a borrower's trust score.
     * @dev    Called by the off-chain AI backend after risk assessment.
     * @param  borrower The address to update.
     * @param  newScore The new trust score (0–100).
     *
     * Emits {TrustScoreUpdated}.
     */
    function updateTrustScore(address borrower, uint8 newScore)
        external
        onlyOwner
    {
        require(borrower != address(0), "LendingPool: zero address");
        require(newScore <= MAX_SCORE, "LendingPool: score > 100");

        uint8 oldScore = trustScores[borrower];
        trustScores[borrower] = newScore;

        emit TrustScoreUpdated(borrower, oldScore, newScore);
    }

    /**
     * @notice Owner marks an active loan as defaulted.
     * @dev    Typically called when dueDate has passed and no repayment was made.
     *         Does NOT slash vouches — that is handled separately in VouchSystem.
     * @param  borrower Address of the defaulting borrower.
     *
     * Emits {LoanDefaulted}.
     */
    function markDefault(address borrower) external onlyOwner {
        Loan storage loan = _loans[borrower];
        require(loan.status == LoanStatus.Active, "LendingPool: not active");

        loan.status = LoanStatus.Defaulted;
        totalActiveLoans--;
        _activeInterestSum -= loan.interestRate;

        // Decrease trust score by 15 (floor at 0)
        uint8 oldScore = trustScores[borrower];
        uint8 penalty  = oldScore >= 15 ? oldScore - 15 : 0;
        trustScores[borrower] = penalty;

        // Sync with Reputation NFT
        try ReputationNFT(reputationNFT).updateReputation(borrower, penalty, loan.amount, false) {} catch {}

        uint256 outstanding = _totalOwed(loan) - loan.repaidAmount;

        emit LoanDefaulted(borrower, loan.amount, outstanding);
        emit TrustScoreUpdated(borrower, oldScore, penalty);
    }

    function mintReputationNFT(address to) external onlyOwner {
        ReputationNFT(reputationNFT).mintReputationNFT(to);
    }

    /**
     * @notice Pause all state-changing operations (emergency stop).
     */
    function pause() external onlyOwner {
        _pause();
    }

    /**
     * @notice Unpause operations.
     */
    function unpause() external onlyOwner {
        _unpause();
    }

    /* ══════════════════════════════════════════
       INTERNAL HELPERS
    ═══════════════════════════════════════════ */

    /**
     * @dev Adjusts the borrower's trust score after full repayment.
     *      - Early repayment (before 75% of term):  +12
     *      - On-time (before dueDate):               +8
     *      - Late (after dueDate):                    +3
     *      Capped at MAX_SCORE (100).
     */
    function _increaseTrustScore(address borrower) internal {
        Loan storage loan = _loans[borrower];
        uint8 oldScore = trustScores[borrower];

        uint8 bump;
        if (block.timestamp <= loan.startTime + ((loan.dueDate - loan.startTime) * 75) / 100) {
            // Repaid before 75% of term → "early"
            bump = SCORE_EARLY;
        } else if (block.timestamp <= loan.dueDate) {
            // Repaid before due date → "on-time"
            bump = SCORE_ONTIME;
        } else {
            // Repaid after due date → "late but repaid"
            bump = SCORE_LATE;
        }

        uint8 newScore = oldScore + bump > MAX_SCORE ? MAX_SCORE : oldScore + bump;
        trustScores[borrower] = newScore;

        // NEW: Update the Reputation NFT (soulbound identity)
        try ReputationNFT(reputationNFT).updateReputation(borrower, newScore, loan.amount, bump >= SCORE_ONTIME) {} catch {}

        emit TrustScoreUpdated(borrower, oldScore, newScore);
    }

    /**
     * @dev Total amount owed = principal + (principal × rate / 10000).
     */
    function _totalOwed(Loan storage loan) internal view returns (uint256) {
        return loan.amount + (loan.amount * loan.interestRate) / 10_000;
    }

    /**
     * @dev Returns the basis-point interest rate for a given path.
     */
    function _rateForPath(LoanPath p) internal pure returns (uint256) {
        if (p == LoanPath.VouchBacked) return RATE_VOUCH;
        if (p == LoanPath.Collateral)  return RATE_COLLATERAL;
        return RATE_TRUST_ONLY;
    }

    /* ══════════════════════════════════════════
       VIEW FUNCTIONS
    ═══════════════════════════════════════════ */

    /**
     * @notice Returns the full Loan struct for a borrower.
     * @param  borrower Address to query.
     * @return loan     The borrower's current/last loan.
     */
    function getLoan(address borrower) external view returns (Loan memory) {
        return _loans[borrower];
    }

    /**
     * @notice Returns a borrower's on-chain trust score.
     * @param  borrower Address to query.
     * @return score    0–100 trust score.
     */
    function getTrustScore(address borrower) external view returns (uint8) {
        return trustScores[borrower];
    }

    /**
     * @notice Returns the TRUST token balance held by this contract.
     * @return balance Includes pool liquidity + locked repayment interest.
     */
    function getPoolBalance() external view returns (uint256) {
        return trustToken.balanceOf(address(this));
    }

    /**
     * @notice Returns the principal a lender has deposited.
     * @param  lender Address to query.
     * @return deposited Amount of TRUST deposited.
     */
    function getLenderBalance(address lender) external view returns (uint256) {
        return lenderDeposits[lender];
    }

    /**
     * @notice Returns the maximum loan amount a borrower is eligible for,
     *         based on their trust score.
     * @param  borrower Address to query.
     * @return limit    Max borrow amount in TRUST (18 decimals).
     */
    function getBorrowLimit(address borrower) public view returns (uint256) {
        uint8 score = trustScores[borrower];
        if (score >= 80) return LIMIT_GOLD;
        if (score >= 60) return LIMIT_SILVER;
        if (score >= 40) return LIMIT_BRONZE;
        return LIMIT_ENTRY;
    }

    /**
     * @notice Returns aggregate pool statistics.
     * @return liquidity       Free TRUST available for new loans.
     * @return activeLoans     Number of loans in Active status.
     * @return lenderCount     Unique lender count.
     * @return avgInterestRate Weighted-average interest rate in basis points
     *                         across active loans (0 if no active loans).
     */
    function getPoolStats()
        external
        view
        returns (
            uint256 liquidity,
            uint256 activeLoans,
            uint256 lenderCount,
            uint256 avgInterestRate
        )
    {
        liquidity       = totalPoolLiquidity;
        activeLoans     = totalActiveLoans;
        lenderCount     = totalLenders;
        avgInterestRate = totalActiveLoans > 0
            ? _activeInterestSum / totalActiveLoans
            : 0;
    }

    /**
     * @notice Returns total amount owed on a borrower's active loan
     *         (principal + interest).
     * @param  borrower Address to query.
     * @return owed Total owed, or 0 if no active loan.
     */
    function getTotalOwed(address borrower) external view returns (uint256) {
        Loan storage loan = _loans[borrower];
        if (loan.status != LoanStatus.Active) return 0;
        return _totalOwed(loan);
    }

    /**
     * @notice Returns remaining balance on a borrower's active loan.
     * @param  borrower Address to query.
     * @return remaining Amount still to be repaid.
     */
    function getRemainingDebt(address borrower) external view returns (uint256) {
        Loan storage loan = _loans[borrower];
        if (loan.status != LoanStatus.Active) return 0;
        uint256 owed = _totalOwed(loan);
        return owed > loan.repaidAmount ? owed - loan.repaidAmount : 0;
    }
}

contracts/ReputationNFT.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Base64.sol";
import "@openzeppelin/contracts/utils/Strings.sol";

/**
 * @title  ReputationNFT
 * @author TrustLend Team
 * @notice Soulbound (non-transferable) ERC-721 NFT representing each user's
 *         on-chain credit identity within the TrustLend ecosystem.
 *
 * @dev    Architecture overview
 *
 *   ┌──────────────┐  mintReputationNFT()   ┌─────────────────┐
 *   │ LendingPool  │ ──────────────────────▶ │  ReputationNFT  │
 *   │  (trusted)   │  updateReputation()     │  (Soulbound)    │
 *   └──────────────┘ ──────────────────────▶ └─────────────────┘
 *                                                    │
 *                          getReputation() / tokenURI() (public reads)
 *                                                    │
 *                                                    ▼
 *                                              Anyone can view
 *
 * Key properties:
 *  • One NFT per wallet — enforced on mint.
 *  • Fully non-transferable — all ERC-721 transfer/approval entry-points revert.
 *  • Only the designated LendingPool address can update scores.
 *  • 100 % on-chain metadata — JSON + SVG art encoded as base64 data URIs.
 *  • Tier ladder: Entry (30-39) → Bronze (40-59) → Silver (60-79) → Gold (80-100).
 */
contract ReputationNFT is ERC721, Ownable {
    using Strings for uint256;
    using Strings for uint8;

    /* ══════════════════════════════════════════
       STRUCTS
    ═══════════════════════════════════════════ */

    /**
     * @notice All on-chain reputation metadata stored per wallet.
     * @param trustScore        Current credit score in range [0, 100].
     * @param tier              Human-readable tier label (Entry/Bronze/Silver/Gold).
     * @param loansRepaid       Total count of successfully repaid loans.
     * @param totalBorrowed     Cumulative principal borrowed (in TRUST token wei).
     * @param totalRepaid       Cumulative amount repaid including interest (in TRUST token wei).
     * @param memberSince       Unix timestamp of the first minted NFT.
     * @param repaymentStreak   Consecutive on-time repayment count; resets on late payment.
     * @param earningArchetype  Behavioural label: "Daily" / "Weekly" / "Seasonal".
     */
    struct ReputationData {
        uint8   trustScore;
        string  tier;
        uint256 loansRepaid;
        uint256 totalBorrowed;
        uint256 totalRepaid;
        uint256 memberSince;
        uint8   repaymentStreak;
        string  earningArchetype;
    }

    /* ══════════════════════════════════════════
       STATE
    ═══════════════════════════════════════════ */

    /// @notice Address of the LendingPool contract authorised to update reputation data.
    address public lendingPoolAddress;

    /// @dev Auto-incrementing token ID counter (starts at 1).
    uint256 private _nextTokenId;

    /// @dev wallet → minted tokenId (0 means no NFT yet).
    mapping(address => uint256) private _walletToTokenId;

    /// @dev tokenId → full on-chain reputation data.
    mapping(uint256 => ReputationData) private _reputationData;

    /* ══════════════════════════════════════════
       CONSTANTS
    ═══════════════════════════════════════════ */

    /// @dev Initial trust score assigned at mint.
    uint8 private constant INITIAL_SCORE = 30;

    /// @dev Tier score boundaries (inclusive lower bounds).
    uint8 private constant SCORE_GOLD   = 80;
    uint8 private constant SCORE_SILVER = 60;
    uint8 private constant SCORE_BRONZE = 40;

    /* ══════════════════════════════════════════
       EVENTS
    ═══════════════════════════════════════════ */

    /**
     * @notice Emitted when a new Reputation NFT is minted for a wallet.
     * @param wallet    The recipient's address.
     * @param tokenId   The newly minted token ID.
     * @param timestamp Block timestamp at time of mint (memberSince).
     */
    event ReputationNFTMinted(
        address indexed wallet,
        uint256 indexed tokenId,
        uint256         timestamp
    );

    /**
     * @notice Emitted each time the LendingPool updates a wallet's reputation.
     * @param wallet     The wallet whose reputation changed.
     * @param oldScore   Trust score before the update.
     * @param newScore   Trust score after the update.
     * @param newTier    Tier label corresponding to `newScore`.
     * @param newStreak  Repayment streak after this update.
     */
    event ReputationUpdated(
        address indexed wallet,
        uint8           oldScore,
        uint8           newScore,
        string          newTier,
        uint8           newStreak
    );

    /**
     * @notice Emitted when the owner changes the authorised LendingPool address.
     * @param oldPool Previous LendingPool address.
     * @param newPool New LendingPool address.
     */
    event LendingPoolUpdated(address indexed oldPool, address indexed newPool);

    /* ══════════════════════════════════════════
       MODIFIERS
    ═══════════════════════════════════════════ */

    /**
     * @dev Restricts a function to only be callable by the registered LendingPool.
     */
    modifier onlyLendingPool() {
        require(
            msg.sender == lendingPoolAddress,
            "ReputationNFT: caller is not LendingPool"
        );
        _;
    }

    /* ══════════════════════════════════════════
       CONSTRUCTOR
    ═══════════════════════════════════════════ */

    /**
     * @notice Deploy the ReputationNFT contract.
     * @dev    Token IDs begin at 1. The LendingPool address can be set later via
     *         `setLendingPool` once the LendingPool is deployed.
     * @param _lendingPool Initial LendingPool address (may be address(0) at deploy
     *                     time and set later).
     */
    constructor(address _lendingPool) ERC721("TrustLend Reputation", "TREP") Ownable(msg.sender) {
        lendingPoolAddress = _lendingPool;
        _nextTokenId = 1;
    }

    /* ══════════════════════════════════════════
       ADMIN FUNCTIONS
    ═══════════════════════════════════════════ */

    /**
     * @notice Update the authorised LendingPool address.
     * @dev    Only the contract owner can call this. Required when re-deploying
     *         the LendingPool or setting it for the first time post-deploy.
     * @param newPool The new LendingPool contract address.
     *
     * Emits {LendingPoolUpdated}.
     */
    function setLendingPool(address newPool) external onlyOwner {
        require(newPool != address(0), "ReputationNFT: zero address");
        address old = lendingPoolAddress;
        lendingPoolAddress = newPool;
        emit LendingPoolUpdated(old, newPool);
    }

    /* ══════════════════════════════════════════
       CORE FUNCTIONS
    ═══════════════════════════════════════════ */

    /**
     * @notice Mint a Reputation NFT for a new TrustLend user.
     * @dev    Called by the LendingPool on a borrower's first-ever loan request.
     *         Each wallet is limited to exactly one NFT (ensured by the
     *         `_walletToTokenId` mapping check).
     *         Initial score is set to 30 (Entry tier) and `memberSince` is
     *         recorded as the current block timestamp.
     * @param  to The wallet address to mint the NFT to.
     *
     * Emits {ReputationNFTMinted}.
     */
    function mintReputationNFT(address to) external onlyLendingPool {
        require(to != address(0),              "ReputationNFT: mint to zero address");
        require(_walletToTokenId[to] == 0,     "ReputationNFT: wallet already has NFT");

        uint256 tokenId = _nextTokenId++;

        _safeMint(to, tokenId);

        _walletToTokenId[to] = tokenId;
        _reputationData[tokenId] = ReputationData({
            trustScore:       INITIAL_SCORE,
            tier:             "Entry",
            loansRepaid:      0,
            totalBorrowed:    0,
            totalRepaid:      0,
            memberSince:      block.timestamp,
            repaymentStreak:  0,
            earningArchetype: "Daily"
        });

        emit ReputationNFTMinted(to, tokenId, block.timestamp);
    }

    /**
     * @notice Update all reputation metadata for a wallet after a loan event.
     * @dev    Only the registered LendingPool may call this function.
     *         Tier is recalculated from `newScore`:
     *           • 30–39 → "Entry"
     *           • 40–59 → "Bronze"
     *           • 60–79 → "Silver"
     *           • 80–100 → "Gold"
     *         Repayment streak is incremented for on-time payments and reset to
     *         zero for late payments. `earningArchetype` is derived from the
     *         updated streak: ≥30 → "Seasonal", ≥7 → "Weekly", else → "Daily".
     *         `loansRepaid`, `totalBorrowed`, and `totalRepaid` are incremented.
     * @param  wallet        The borrower's wallet address.
     * @param  newScore      New trust score (0–100).
     * @param  loanAmount    Principal of the loan just processed (TRUST wei).
     * @param  repaidOnTime  `true` if repayment was made before or on the due date.
     *
     * Emits {ReputationUpdated}.
     */
    function updateReputation(
        address wallet,
        uint8   newScore,
        uint256 loanAmount,
        bool    repaidOnTime
    ) external onlyLendingPool {
        require(wallet != address(0),         "ReputationNFT: zero address");
        require(newScore <= 100,              "ReputationNFT: score exceeds 100");

        uint256 tokenId = _walletToTokenId[wallet];
        require(tokenId != 0,                "ReputationNFT: wallet has no NFT");

        ReputationData storage data = _reputationData[tokenId];

        uint8  oldScore = data.trustScore;
        string memory newTier = _tierFromScore(newScore);

        // Update streak
        uint8 newStreak;
        if (repaidOnTime) {
            // Cap streak at 255 (uint8 max) to avoid overflow
            newStreak = data.repaymentStreak < type(uint8).max
                ? data.repaymentStreak + 1
                : type(uint8).max;
        } else {
            newStreak = 0;
        }

        // Derive earning archetype from streak
        string memory archetype;
        if (newStreak >= 30) {
            archetype = "Seasonal";
        } else if (newStreak >= 7) {
            archetype = "Weekly";
        } else {
            archetype = "Daily";
        }

        // Write all updates
        data.trustScore       = newScore;
        data.tier             = newTier;
        data.loansRepaid      += 1;
        data.totalBorrowed    += loanAmount;
        data.totalRepaid      += loanAmount; // caller may pass exact repaid amount; using loanAmount as principal proxy
        data.repaymentStreak  = newStreak;
        data.earningArchetype = archetype;

        emit ReputationUpdated(wallet, oldScore, newScore, newTier, newStreak);
    }

    /* ══════════════════════════════════════════
       VIEW FUNCTIONS
    ═══════════════════════════════════════════ */

    /**
     * @notice Retrieve the full on-chain reputation data for a wallet.
     * @param  wallet Address to query.
     * @return        A {ReputationData} struct with all fields populated.
     */
    function getReputation(address wallet) external view returns (ReputationData memory) {
        uint256 tokenId = _walletToTokenId[wallet];
        require(tokenId != 0, "ReputationNFT: wallet has no NFT");
        return _reputationData[tokenId];
    }

    /**
     * @notice Retrieve just the tier label for a wallet.
     * @param  wallet Address to query.
     * @return        One of "Entry", "Bronze", "Silver", or "Gold".
     */
    function getTier(address wallet) external view returns (string memory) {
        uint256 tokenId = _walletToTokenId[wallet];
        require(tokenId != 0, "ReputationNFT: wallet has no NFT");
        return _reputationData[tokenId].tier;
    }

    /**
     * @notice Check whether a wallet holds a Reputation NFT.
     * @param  wallet Address to query.
     * @return        `true` if the wallet has been minted an NFT, `false` otherwise.
     */
    function hasNFT(address wallet) external view returns (bool) {
        return _walletToTokenId[wallet] != 0;
    }

    /**
     * @notice Returns the token ID owned by a wallet, or 0 if none.
     * @param  wallet Address to query.
     * @return        The token ID, or 0.
     */
    function tokenIdOf(address wallet) external view returns (uint256) {
        return _walletToTokenId[wallet];
    }

    /* ══════════════════════════════════════════
       TOKEN URI (FULLY ON-CHAIN)
    ═══════════════════════════════════════════ */

    /**
     * @notice Returns a base64-encoded data URI containing JSON metadata and
     *         an on-chain SVG image. No external IPFS or server dependency.
     * @dev    SVG shows the trust score (large numeral) and tier name against a
     *         rich dark background with gold typography — simple yet impactful.
     * @param  tokenId The NFT token ID to query.
     * @return         A `data:application/json;base64,...` URI string.
     */
    function tokenURI(uint256 tokenId) public view override returns (string memory) {
        _requireOwned(tokenId);

        ReputationData memory data = _reputationData[tokenId];

        string memory svgImage = _buildSVG(data);
        string memory imageDataURI = string(
            abi.encodePacked(
                "data:image/svg+xml;base64,",
                Base64.encode(bytes(svgImage))
            )
        );

        string memory json = string(
            abi.encodePacked(
                '{"name":"TrustLend Reputation #', tokenId.toString(), '",',
                '"description":"Soulbound on-chain credit identity for the TrustLend protocol.",',
                '"image":"', imageDataURI, '",',
                '"attributes":[',
                    '{"trait_type":"Trust Score","value":', uint256(data.trustScore).toString(), '},',
                    '{"trait_type":"Tier","value":"', data.tier, '"},',
                    '{"trait_type":"Loans Repaid","value":', data.loansRepaid.toString(), '},',
                    '{"trait_type":"Total Borrowed","value":', data.totalBorrowed.toString(), '},',
                    '{"trait_type":"Total Repaid","value":', data.totalRepaid.toString(), '},',
                    '{"trait_type":"Member Since","value":', data.memberSince.toString(), '},',
                    '{"trait_type":"Repayment Streak","value":', uint256(data.repaymentStreak).toString(), '},',
                    '{"trait_type":"Earning Archetype","value":"', data.earningArchetype, '"}',
                ']}'
            )
        );

        return string(
            abi.encodePacked(
                "data:application/json;base64,",
                Base64.encode(bytes(json))
            )
        );
    }

    /* ══════════════════════════════════════════
       SOULBOUND — TRANSFER OVERRIDES
    ═══════════════════════════════════════════ */

    /**
     * @dev Override to enforce soulbound constraint.
     *      All token transfers (including minting path via {_safeMint}) pass
     *      through {_update}. We allow minting (from == address(0)) but block
     *      any movement once an NFT is minted.
     */
    function _update(
        address to,
        uint256 tokenId,
        address auth
    ) internal override returns (address) {
        address from = _ownerOf(tokenId);
        if (from != address(0) && to != address(0)) {
            revert("ReputationNFT: Soulbound \u2014 non-transferable");
        }
        return super._update(to, tokenId, auth);
    }

    /**
     * @notice Blocked. ReputationNFTs are non-transferable.
     * @dev    Always reverts with a soulbound error message.
     */
    function transferFrom(
        address, /* from */
        address, /* to */
        uint256  /* tokenId */
    ) public pure override {
        revert("ReputationNFT: Soulbound \u2014 non-transferable");
    }

    /**
     * @notice Blocked. ReputationNFTs are non-transferable.
     * @dev    Always reverts with a soulbound error message.
     */
    function safeTransferFrom(
        address, /* from */
        address, /* to */
        uint256, /* tokenId */
        bytes memory /* data */
    ) public pure override {
        revert("ReputationNFT: Soulbound \u2014 non-transferable");
    }

    /**
     * @notice Blocked. Token-level approvals serve no purpose on a soulbound token.
     * @dev    Always reverts with a soulbound error message.
     */
    function approve(
        address, /* to */
        uint256  /* tokenId */
    ) public pure override {
        revert("ReputationNFT: Soulbound \u2014 non-transferable");
    }

    /**
     * @notice Blocked. Operator approvals serve no purpose on a soulbound token.
     * @dev    Always reverts with a soulbound error message.
     */
    function setApprovalForAll(
        address, /* operator */
        bool     /* approved */
    ) public pure override {
        revert("ReputationNFT: Soulbound \u2014 non-transferable");
    }

    /* ══════════════════════════════════════════
       INTERNAL HELPERS
    ═══════════════════════════════════════════ */

    /**
     * @dev Derives the tier label string from a numeric trust score.
     * @param score Trust score in [0, 100].
     * @return      Tier string: "Gold", "Silver", "Bronze", or "Entry".
     */
    function _tierFromScore(uint8 score) internal pure returns (string memory) {
        if (score >= SCORE_GOLD)   return "Gold";
        if (score >= SCORE_SILVER) return "Silver";
        if (score >= SCORE_BRONZE) return "Bronze";
        return "Entry";
    }

    /**
     * @dev Builds the on-chain SVG art for a given ReputationData snapshot.
     *      Visual design:
     *        • Dark charcoal background (#0f0f1a)
     *        • Subtle gold radial glow behind the score circle
     *        • Large gold score numeral centred in a glowing ring
     *        • Tier label below in a gold accent font
     *        • Protocol name and streak badge at the bottom
     * @param data Full ReputationData struct for the NFT.
     * @return     Raw SVG mark-up as a string.
     */
    function _buildSVG(ReputationData memory data) internal pure returns (string memory) {
        string memory scoreStr = uint256(data.trustScore).toString();
        string memory streakStr = uint256(data.repaymentStreak).toString();

        // Pick accent colour per tier
        string memory accentColour = _tierColour(data.tier);

        return string(
            abi.encodePacked(
                '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 400 560" width="400" height="560">',

                // ── Definitions ────────────────────────────────────────────
                '<defs>',
                    '<radialGradient id="bg" cx="50%" cy="40%" r="70%">',
                        '<stop offset="0%" stop-color="#1a1a2e"/>',
                        '<stop offset="100%" stop-color="#0a0a12"/>',
                    '</radialGradient>',
                    '<radialGradient id="glow" cx="50%" cy="50%" r="50%">',
                        '<stop offset="0%" stop-color="', accentColour, '" stop-opacity="0.35"/>',
                        '<stop offset="100%" stop-color="', accentColour, '" stop-opacity="0"/>',
                    '</radialGradient>',
                    '<filter id="blur">',
                        '<feGaussianBlur stdDeviation="18"/>',
                    '</filter>',
                    '<linearGradient id="ringGrad" x1="0%" y1="0%" x2="100%" y2="100%">',
                        '<stop offset="0%" stop-color="', accentColour, '"/>',
                        '<stop offset="100%" stop-color="#ffffff" stop-opacity="0.4"/>',
                    '</linearGradient>',
                '</defs>',

                // ── Background ──────────────────────────────────────────────
                '<rect width="400" height="560" rx="24" fill="url(#bg)"/>',

                // ── Glow blob ───────────────────────────────────────────────
                '<circle cx="200" cy="210" r="130" fill="url(#glow)" filter="url(#blur)"/>',

                // ── Score ring ──────────────────────────────────────────────
                '<circle cx="200" cy="210" r="110" fill="none" stroke="url(#ringGrad)" stroke-width="3" opacity="0.6"/>',
                '<circle cx="200" cy="210" r="95"  fill="#0f0f1a" stroke="', accentColour, '" stroke-width="1.5" opacity="0.3"/>',

                // ── Score numeral ───────────────────────────────────────────
                '<text x="200" y="238"',
                '  font-family="\'Arial Black\', sans-serif"',
                '  font-size="80" font-weight="900"',
                '  fill="', accentColour, '"',
                '  text-anchor="middle"',
                '  dominant-baseline="middle">',
                scoreStr,
                '</text>',

                // ── "/100" sub-label ─────────────────────────────────────────
                '<text x="200" y="278"',
                '  font-family="Arial, sans-serif"',
                '  font-size="14" fill="', accentColour, '" opacity="0.55"',
                '  text-anchor="middle">/ 100</text>',

                // ── Tier badge ───────────────────────────────────────────────
                '<rect x="130" y="335" width="140" height="38" rx="19"',
                '  fill="none" stroke="', accentColour, '" stroke-width="1.5" opacity="0.7"/>',
                '<text x="200" y="359"',
                '  font-family="Arial, sans-serif"',
                '  font-size="18" font-weight="700"',
                '  fill="', accentColour, '"',
                '  text-anchor="middle"',
                '  letter-spacing="3">',
                _toUpperCase(data.tier),
                '</text>',

                // ── Stats row ────────────────────────────────────────────────
                '<text x="200" y="415"',
                '  font-family="Arial, sans-serif"',
                '  font-size="12" fill="#888" text-anchor="middle">',
                'LOANS REPAID &amp; STREAK',
                '</text>',
                '<text x="130" y="440"',
                '  font-family="Arial, sans-serif"',
                '  font-size="22" font-weight="700"',
                '  fill="#ffffff" text-anchor="middle">',
                data.loansRepaid.toString(),
                '</text>',
                '<text x="270" y="440"',
                '  font-family="Arial, sans-serif"',
                '  font-size="22" font-weight="700"',
                '  fill="', accentColour, '" text-anchor="middle">',
                streakStr, 'x',
                '</text>',
                '<text x="130" y="458" font-family="Arial,sans-serif" font-size="10" fill="#555" text-anchor="middle">loans</text>',
                '<text x="270" y="458" font-family="Arial,sans-serif" font-size="10" fill="#555" text-anchor="middle">streak</text>',

                // ── Archetype ────────────────────────────────────────────────
                '<text x="200" y="498"',
                '  font-family="Arial, sans-serif"',
                '  font-size="11" fill="#666" text-anchor="middle" letter-spacing="2">',
                _toUpperCase(data.earningArchetype), ' EARNER',
                '</text>',

                // ── Protocol name ────────────────────────────────────────────
                '<text x="200" y="535"',
                '  font-family="\'Arial Black\', sans-serif"',
                '  font-size="13" fill="', accentColour, '"',
                '  opacity="0.5" text-anchor="middle" letter-spacing="4">',
                'TRUSTLEND',
                '</text>',

                // ── Corner ornaments ─────────────────────────────────────────
                '<circle cx="30"  cy="30"  r="4" fill="', accentColour, '" opacity="0.25"/>',
                '<circle cx="370" cy="30"  r="4" fill="', accentColour, '" opacity="0.25"/>',
                '<circle cx="30"  cy="530" r="4" fill="', accentColour, '" opacity="0.25"/>',
                '<circle cx="370" cy="530" r="4" fill="', accentColour, '" opacity="0.25"/>',

                '</svg>'
            )
        );
    }

    /**
     * @dev Returns the hex accent colour for each tier.
     * @param tier Tier label string.
     * @return     Hex colour string (CSS-compatible).
     */
    function _tierColour(string memory tier) internal pure returns (string memory) {
        bytes32 h = keccak256(bytes(tier));
        if (h == keccak256(bytes("Gold")))   return "#FFD700";
        if (h == keccak256(bytes("Silver"))) return "#C0C0C0";
        if (h == keccak256(bytes("Bronze"))) return "#CD7F32";
        return "#8B8FA8"; // Entry — muted blue-grey
    }

    /**
     * @dev Naive toUpperCase for short ASCII tier/archetype strings.
     *      Only converts lowercase a-z; safe for the fixed set of values used here.
     * @param str Input string.
     * @return    Upper-cased string.
     */
    function _toUpperCase(string memory str) internal pure returns (string memory) {
        bytes memory b = bytes(str);
        bytes memory upper = new bytes(b.length);
        for (uint256 i = 0; i < b.length; i++) {
            uint8 c = uint8(b[i]);
            upper[i] = (c >= 97 && c <= 122) ? bytes1(c - 32) : bytes1(c);
        }
        return string(upper);
    }
}

contracts/StableToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title StableToken
 * @notice Mock stablecoin (USDC-like) used across TrustLend for all transfers.
 * Deployer receives the initial supply and can mint more for testing.
 */
contract StableToken is ERC20, Ownable {
    constructor() ERC20("TrustLend Dollar", "TLD") Ownable(msg.sender) {
        // Mint 1,000,000 TLD to deployer
        _mint(msg.sender, 1_000_000 * 10 ** decimals());
    }

    /// @notice Owner can mint additional tokens (for seeding test accounts)
    function mint(address to, uint256 amount) external onlyOwner {
        _mint(to, amount);
    }
}

contracts/TrustToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title TrustToken
 * @notice ERC-20 token for the TrustLend micro-lending platform on Polygon Amoy.
 *
 *  - Name:           TrustLend Token
 *  - Symbol:         TRUST
 *  - Decimals:       18
 *  - Initial Supply: 1,000,000 TRUST minted to deployer
 *  - Faucet:         Anyone can claim 1,000 TRUST every 24 hours
 *  - Owner mint:     Deployer can mint more for top-ups
 */
contract TrustToken is ERC20, Ownable {
    /* ── Faucet config ── */
    uint256 public constant FAUCET_AMOUNT   = 1_000 * 1e18;  // 1,000 TRUST
    uint256 public constant FAUCET_COOLDOWN = 24 hours;

    /// @notice Last claim timestamp per wallet
    mapping(address => uint256) public lastClaimed;

    /* ── Events ── */
    event TokensClaimed(address indexed claimer, uint256 amount, uint256 timestamp);

    /* ── Constructor ── */
    constructor() ERC20("TrustLend Token", "TRUST") Ownable(msg.sender) {
        // Mint 1,000,000 TRUST to deployer
        _mint(msg.sender, 1_000_000 * 10 ** decimals());
    }

    /* ── Faucet ── */

    /**
     * @notice Claim 1,000 TRUST test tokens. Callable once every 24 hours.
     * @dev    Perfect for hackathon demos — judges can get tokens themselves.
     */
    function claimTestTokens() external {
        require(
            block.timestamp >= lastClaimed[msg.sender] + FAUCET_COOLDOWN,
            "TrustToken: wait 24h between claims"
        );

        lastClaimed[msg.sender] = block.timestamp;
        _mint(msg.sender, FAUCET_AMOUNT);

        emit TokensClaimed(msg.sender, FAUCET_AMOUNT, block.timestamp);
    }

    /**
     * @notice How many seconds until the caller can claim again.
     * @return 0 if claimable now, otherwise seconds remaining.
     */
    function timeUntilNextClaim(address account) external view returns (uint256) {
        uint256 nextTime = lastClaimed[account] + FAUCET_COOLDOWN;
        if (block.timestamp >= nextTime) return 0;
        return nextTime - block.timestamp;
    }

    /* ── Owner-only mint ── */

    /**
     * @notice Owner mints additional tokens (for pool seeding, test accounts, etc.)
     */
    function mint(address to, uint256 amount) external onlyOwner {
        _mint(to, amount);
    }
}

